import { APP_CONFIG } from '../data/config.js';

// STEP 2 hub: a single page linking EVERY state hub and EVERY state×dispute deep
// page with real, static, descriptive <a href> anchors. Linked from the homepage so
// the whole programmatic-SEO cluster is reachable in <=2 clicks and is no longer
// crawl-orphaned. Generated by build-pages.js so it stays in sync with the data.
export function renderHub(states, disputes) {
  const sections = states.map(state => {
    const links = disputes.map(d =>
      `      <li><a href="/${state.slug}/${d.slug}">${escapeHtml(state.name)} ${escapeHtml(d.name)}</a></li>`
    ).join('\n');
    return `  <section class="hub-state">
    <h2><a class="hub-state-link" href="/${state.slug}">${escapeHtml(state.name)} Property Tax Appeal Letters</a></h2>
    <ul class="hub-list">
${links}
    </ul>
  </section>`;
  }).join('\n');

  const totalPages = states.length * disputes.length;

  return `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>All Property Tax Appeal Letters by State — ${states.length} States, ${disputes.length} Dispute Types | ${APP_CONFIG.name}</title>
<meta name="description" content="Browse every state-specific property tax appeal letter ${APP_CONFIG.name} offers — ${totalPages} guides across ${states.length} states and ${disputes.length} dispute types. AI-generated, attorney-quality, $${APP_CONFIG.price} flat.">
<link rel="canonical" href="https://${APP_CONFIG.domain}/letters">
<meta property="og:title" content="All Property Tax Appeal Letters by State | ${APP_CONFIG.name}">
<meta property="og:description" content="Every state-specific property tax appeal letter, organized by state and dispute type.">
<meta property="og:url" content="https://${APP_CONFIG.domain}/letters">
<link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://fonts.googleapis.com/css2?family=Fraunces:wght@700;900&family=DM+Sans:wght@300;400;500;600;700&display=swap" rel="stylesheet">
<style>
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
body{font-family:'DM Sans',system-ui,sans-serif;background:#f8fafc;color:#0f0f0f;line-height:1.6}
nav{position:sticky;top:0;z-index:100;background:rgba(248,250,252,0.92);backdrop-filter:blur(12px);border-bottom:1px solid #dde3ec;padding:14px 28px;display:flex;justify-content:space-between;align-items:center}
.nav-brand{display:flex;align-items:center;gap:10px;text-decoration:none}
.nav-icon{width:32px;height:32px;background:linear-gradient(135deg,${APP_CONFIG.primaryColor},#0d1f33);border-radius:7px;display:flex;align-items:center;justify-content:center;font-size:15px}
.nav-name{font-family:'Fraunces',Georgia,serif;font-size:17px;font-weight:700;color:#0f0f0f}
.nav-cta{background:${APP_CONFIG.primaryColor};color:#fff;padding:9px 20px;border-radius:6px;text-decoration:none;font-size:14px;font-weight:600}
.hero{background:linear-gradient(160deg,#0a1a2a 0%,#143a5a 60%,#0a3a4a 100%);color:#fff;padding:72px 24px;text-align:center}
.hero h1{font-family:'Fraunces',Georgia,serif;font-size:clamp(30px,5vw,48px);font-weight:900;line-height:1.12;margin-bottom:16px;letter-spacing:-0.02em}
.hero p{font-size:18px;color:rgba(255,255,255,0.85);max-width:680px;margin:0 auto;font-weight:300}
.container{max-width:1100px;margin:0 auto;padding:56px 24px}
.intro{font-size:17px;color:#3a3a3a;line-height:1.75;max-width:820px;margin-bottom:40px}
.hub-state{margin-bottom:40px;background:#fff;border:1px solid #dde3ec;border-radius:12px;padding:28px 32px}
.hub-state h2{font-family:'Fraunces',Georgia,serif;font-size:24px;font-weight:900;margin-bottom:16px;letter-spacing:-0.01em}
.hub-state-link{color:${APP_CONFIG.primaryColor};text-decoration:none}
.hub-state-link:hover{text-decoration:underline}
.hub-list{list-style:none;display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:8px 24px}
.hub-list a{color:#1f2937;text-decoration:none;font-size:15px;font-weight:500;display:block;padding:6px 0;border-bottom:1px solid #f1f5f9}
.hub-list a:hover{color:${APP_CONFIG.primaryColor}}
footer{background:#0f0f0f;color:rgba(255,255,255,0.5);text-align:center;padding:32px 24px;font-size:12px}
footer a{color:rgba(255,255,255,0.7);text-decoration:none}
</style>
</head>
<body>
<nav>
  <a class="nav-brand" href="/">
    <div class="nav-icon">${APP_CONFIG.brandIcon}</div>
    <span class="nav-name">${APP_CONFIG.name}</span>
  </a>
  <a class="nav-cta" href="${APP_CONFIG.payhipUrl}">${APP_CONFIG.ctaText} →</a>
</nav>
<section class="hero">
  <h1>All Property Tax Appeal Letters by State</h1>
  <p>Every state-specific property tax appeal letter we offer — ${totalPages} guides across ${states.length} states and ${disputes.length} dispute types. Pick your state and dispute below.</p>
</section>
<div class="container">
  <p class="intro">An over-assessed home means an over-sized tax bill — and the assessor's number is not the final word. ${APP_CONFIG.name} provides state-specific property tax appeal and exemption letters citing the relevant statutes and deadlines for your state. Browse the full library below, organized by state.</p>
${sections}
</div>
<footer>
  <p>${APP_CONFIG.name} &middot; &copy; 2026 The Super Simple Software Company &middot; <a href="mailto:support@buyappsonce.com">support@buyappsonce.com</a></p>
  <p style="margin-top:8px;font-size:11px;opacity:0.6">Legal Disclaimer: This page provides general information about property tax appeals and is not legal or tax advice. Statutes and deadlines change; verify current law or consult a licensed professional for your specific situation.</p>
</footer>
</body>
</html>`;
}

function escapeHtml(s) {
  if (!s) return '';
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#039;');
}
